const question = $json.body.question.toLowerCase();
let context_type = 'general';

if (question.includes('revenue') || question.includes('sales') || question.includes('order')) {
  context_type = 'revenue';
} else if (question.includes('product') || question.includes('sku') || question.includes('selling')) {
  context_type = 'product';
} else if (question.includes('ad') || question.includes('google') || question.includes('roas') || question.includes('cpc')) {
  context_type = 'ads';
} else if (question.includes('email') || question.includes('mailchimp') || question.includes('campaign') || question.includes('subscriber')) {
  context_type = 'email';
} else if (question.includes('ai') || question.includes('chatgpt') || question.includes('perplexity') || question.includes('referral')) {
  context_type = 'ai_traffic';
}

return {
  json: {
    tenant_id: $json.body.tenant_id,
    question: $json.body.question,
    context_type
  }
};

const data = $json;
const question = $('Classify Question Intent').item.json.question;
const contextType = $('Classify Question Intent').item.json.context_type;

const systemPrompt = `You are PulseCommerce AI Analyst — a data-aware assistant for an e-commerce brand.
You have access to the following live data context:

Revenue Summary: ${JSON.stringify(data.revenue_summary)}
Top Products: ${JSON.stringify(data.top_products)}
Google Ads: ${JSON.stringify(data.google_ads)}
Email Campaigns: ${JSON.stringify(data.email_campaigns)}
AI Referrals: ${JSON.stringify(data.ai_referrals)}

Answer the user's question using ONLY the data provided. Be specific with numbers.
Format currency as GBP X,XXX.XX. Highlight key insights and actionable recommendations.
Keep responses concise but data-rich.`;

return {
  json: {
    system_prompt: systemPrompt,
    question,
    context_type: contextType,
    context_modules: {
      revenue: !!data.revenue_summary,
      products: !!data.top_products,
      google_ads: !!data.google_ads,
      email: !!data.email_campaigns,
      ai_referrals: !!data.ai_referrals
    }
  }
};

const response = $json;
const contextModules = $('Build AI Prompt').item.json.context_modules;

return {
  json: {
    answer: response.content?.[0]?.text || 'Unable to generate response.',
    context_loaded: contextModules,
    model: response.model,
    usage: response.usage
  }
};
